// // This module decodes a 4-bit input to produce a 2-bit output indicating the position of the lowest-order bit set to 1.
module priority_encoder_4bit (
    input [3:0] a,
    output reg [1:0] y
);

    always @(*) begin
        if (a[3]) y = 2'b11;
        else if (a[2]) y = 2'b10;
        else if (a[1]) y = 2'b01;
        else if (a[0]) y = 2'b00;
        else y = 2'b00; // Default case when all bits are 0
    end

endmodule
